mapper.insert:

	SELECT SEQ_CHAMP_NO.NEXTVAL FROM DUAL

INSERT INTO CHAMP_INFO (
CHAMP_NO, CHAMP_NAME, CHAMP_POSITION,
CHAMP_ROLES, CHAMP_IMG
) VALUES (
#{champNo}, #{champName},
#{champPosition}, #{champRoles}, #{champImg}
)

INSERT INTO
CHAMP_SKIN_INFO (
CHAMP_SKIN_NO, CHAMP_NO, CHAMP_SKIN_NAME,
CHAMP_SKIN_IMG
) VALUES (
SEQ_CHAMP_SKIN_NO.NEXTVAL, #{champNo},
#{champSkinName}, #{champSkinImg}
)
